const posts = $input.all().map(item => item.json);

function getDaysOld(timestamp){
  const now = Date.now();
  const diff = now - timestamp;
  return Math.floor(diff / (1000 * 60 * 60 * 24));
}

function detectContentType(post){
  if(post.video) return "video";
  if(post.postImages && post.postImages.length > 0) return "image";
  return "text";
}

function extractImages(images){

  if(!images || images.length === 0){
    return {
      images: "",
      count: 0
    };
  }

  const urls = images.map(img => img.url);

  return {
    images: urls.join("\n"), // clean format for Google Sheets
    count: urls.length
  };
}

function countHashtags(text){
  if(!text) return 0;
  const matches = text.match(/#\w+/g);
  return matches ? matches.length : 0;
}

function detectLinks(text){
  if(!text) return false;
  return /(https?:\/\/)/.test(text);
}

// Convert UTC timestamp to IST
function getISTDate(timestamp){
  return new Date(timestamp + (5.5 * 60 * 60 * 1000));
}

function getPostingDay(timestamp){
  const date = getISTDate(timestamp);
  return date.toLocaleString("en-US", { weekday: "long" });
}

function getPostingHour(timestamp){
  const date = getISTDate(timestamp);
  return date.getHours();
}

function getTimeBucket(hour){

  if(hour >= 5 && hour < 9) return "Morning";
  if(hour >= 9 && hour < 12) return "Late Morning";
  if(hour >= 12 && hour < 15) return "Afternoon";
  if(hour >= 15 && hour < 18) return "Evening";
  if(hour >= 18 && hour < 22) return "Night";

  return "Late Night";
}

const cleaned = posts.map(post => {

  const likes = post.engagement?.likes || 0;
  const comments = post.engagement?.comments || 0;
  const shares = post.engagement?.shares || 0;

  const totalEngagement = likes + comments + shares;

  const engagementScore =
    (likes * 1) +
    (comments * 3) +
    (shares * 5);

  let performance = "Low";

  if(engagementScore > 50) performance = "High";
  else if(engagementScore > 20) performance = "Medium";

  const postingHour = getPostingHour(post.postedAt.timestamp);

  const images = extractImages(post.postImages);

  return {

    post_id: post.id,

    linkedin_post_url: post.linkedinUrl,

    post_content: post.content,

    linkedin_profile_id: post.author?.publicIdentifier,

    posted_date: getISTDate(post.postedAt.timestamp).toISOString().split("T")[0],

    posting_day: getPostingDay(post.postedAt.timestamp),

    posting_hour: postingHour,

    posting_time_bucket: getTimeBucket(postingHour),

    posted_ageing_days: getDaysOld(post.postedAt.timestamp),

    content_type: detectContentType(post),

    post_images: images.images,

    image_count: images.count,

    has_links: detectLinks(post.content),

    hashtags_count: countHashtags(post.content),

    post_length: post.content ? post.content.length : 0,

    post_likes: likes,

    post_comments: comments,

    post_shares: shares,

    total_engagement: totalEngagement,

    engagement_score: engagementScore,

    post_performance: performance

  };

});

return cleaned.map(i => ({ json: i }));

