const data = $input.first().json;

const youtubeVideos = data.youtube_videos || [];
const youtubeChannel = data.youtube_channel?.[0] || {};
const linkedinProfile = data.linkedin_profile?.[0] || {};
const linkedinPosts = data.linkedin_posts || [];


/* =============================
YOUTUBE ANALYSIS
============================= */

const totalVideoViews = youtubeVideos.reduce((sum,v)=> sum + (v.view_count || 0),0);
const totalVideoLikes = youtubeVideos.reduce((sum,v)=> sum + (v.like_count || 0),0);
const totalVideoComments = youtubeVideos.reduce((sum,v)=> sum + (v.comment_count || 0),0);

const youtube = {

  // Channel Info
  channel_id: youtubeChannel.channel_id,
  channel_title: youtubeChannel.title,
  custom_url: youtubeChannel.custom_url,
  channel_created_date: youtubeChannel.channel_created_date,
  subscriber_count: youtubeChannel.subscriber_count,
  channel_total_views: youtubeChannel.view_count,
  channel_total_videos: youtubeChannel.video_count,

  // Scraped Video Data
  total_videos_scraped: youtubeVideos.length,

  // Aggregated Metrics
  total_video_views: totalVideoViews,
  total_video_likes: totalVideoLikes,
  total_video_comments: totalVideoComments,

  avg_views_per_video: youtubeVideos.length
    ? Math.round(totalVideoViews / youtubeVideos.length)
    : 0,

  avg_likes_per_video: youtubeVideos.length
    ? Math.round(totalVideoLikes / youtubeVideos.length)
    : 0,

  avg_comments_per_video: youtubeVideos.length
    ? Math.round(totalVideoComments / youtubeVideos.length)
    : 0,

  videos: youtubeVideos
};


/* =============================
LINKEDIN ANALYSIS
============================= */

// Basic post metrics
const totalPosts = linkedinPosts.length;

const totalLikes = linkedinPosts.reduce((sum,p)=> sum + (p.post_likes || 0),0);
const totalComments = linkedinPosts.reduce((sum,p)=> sum + (p.post_comments || 0),0);
const totalShares = linkedinPosts.reduce((sum,p)=> sum + (p.post_shares || 0),0);

const avgEngagement = totalPosts
  ? Math.round(linkedinPosts.reduce((sum,p)=> sum + (p.total_engagement || 0),0) / totalPosts)
  : 0;


// Best performing post
const bestPost = [...linkedinPosts].sort(
  (a,b)=> (b.engagement_score || 0) - (a.engagement_score || 0)
)[0] || {};


// Best posting day calculation
const dayCount = {};

linkedinPosts.forEach(p=>{
  dayCount[p.post_day] = (dayCount[p.post_day] || 0) + (p.total_engagement || 0);
});

const bestDay = Object.keys(dayCount).sort((a,b)=> dayCount[b] - dayCount[a])[0] || "";


// Profile age calculation (handles DD-MM-YYYY)
let profileAge = "Unknown";

if (linkedinProfile.linkedin_account_created_date){

  const parts = linkedinProfile.linkedin_account_created_date.split("-");
  const created = new Date(parts[2], parts[1]-1, parts[0]);
  const now = new Date();

  const diffYears = now.getFullYear() - created.getFullYear();

  profileAge = `${diffYears} years`;
}


// Final LinkedIn Object
const linkedin = {

  profile: {
    profile_id: linkedinProfile.linkedin_profile_id,
    profile_url: linkedinProfile.linkedin_profile_url,
    location: linkedinProfile.location,
    followers: linkedinProfile.followers_count,
    connections: linkedinProfile.connection_count,

    account_creation_date:
      linkedinProfile.linkedin_account_created_date || "Not provided",

    profile_age: profileAge
  },

  analytics: {
    total_posts_analyzed: totalPosts,
    total_likes: totalLikes,
    total_comments: totalComments,
    total_shares: totalShares,
    avg_post_engagement: avgEngagement,

    best_post_id: bestPost.post_id || "",
    best_post_score: bestPost.engagement_score || 0,
    best_post_day: bestDay
  },

  posts: linkedinPosts.map(p => ({
    post_id: p.post_id,
    post_url: p.linkedin_post_url,
    post_content: p.post_content,
    posted_date: p.posted_date,
    post_day: p.post_day,
    posting_hour: p.posting_hour,
    posting_time_bucket: p.posting_time_bucket,
    content_type: p.content_type,
    hashtags_count: p.hashtags_count,
    post_length: p.post_length,
    image_count: p.image_count,
    has_links: p.has_links,
    post_likes: p.post_likes,
    post_comments: p.post_comments,
    post_shares: p.post_shares,
    total_engagement: p.total_engagement,
    engagement_score: p.engagement_score,
    post_performance: p.post_performance
  }))
};


return [
{
json:{
youtube,
linkedin
}
}
];

