const raw = $input.first().json.output;

// split sections
const sections = raw.split(/\n\d+\.\s/).map(s => s.trim()).filter(Boolean);

function cleanLines(text){
  return text
    .split("\n")
    .map(l => l.replace(/^- /,"").trim())
    .filter(Boolean);
}

// -------- PROFILE OVERVIEW --------
const profile_overview = cleanLines(sections[0] || "");

// -------- POSTS --------
const postsRaw = sections[1] || "";
const postBlocks = postsRaw.split(/Post \d+:/).filter(Boolean);

const posts = postBlocks.map(block=>{
  const lines = cleanLines(block);
  const obj = {};

  lines.forEach(line=>{
    const parts = line.split(":");
    const key = parts.shift().trim().toLowerCase().replace(/ /g,"_");
    const value = parts.join(":").trim();
    obj[key] = value;
  });

  return obj;
});

// -------- OTHER SECTIONS --------
const aggregated_post_statistics = cleanLines(sections[2] || "");
const engagement_analysis = cleanLines(sections[3] || "");
const content_performance_analysis = cleanLines(sections[4] || "");
const posting_behavior_analysis = cleanLines(sections[5] || "");
const top_performing_content = cleanLines(sections[6] || "");
const audience_interaction_insights = cleanLines(sections[7] || "");
const strategic_recommendations = cleanLines(sections[8] || "");

return [
{
json:{
profile_overview,
posts,
aggregated_post_statistics,
engagement_analysis,
content_performance_analysis,
posting_behavior_analysis,
top_performing_content,
audience_interaction_insights,
strategic_recommendations
}
}
];

